// Extract a normalized message from the Meta webhook payload.
const root = $input.first().json;
const body = root.body || root;
function parse(b){
  try{
    const v = b.entry && b.entry[0] && b.entry[0].changes && b.entry[0].changes[0] && b.entry[0].changes[0].value;
    const m = v && v.messages && v.messages[0];
    if(!m) return null;
    return {
      phoneNumberId: v.metadata && v.metadata.phone_number_id,
      from: m.from,
      text: (m.text && m.text.body) || (m.button && m.button.text) || (m.interactive && ((m.interactive.list_reply||{}).title || (m.interactive.button_reply||{}).title)) || '',
      messageId: m.id,
      contactName: v.contacts && v.contacts[0] && v.contacts[0].profile && v.contacts[0].profile.name || null,
    };
  }catch(e){ return null; }
}
const payload = parse(body);
return [{ json: { payload, skip: !payload } }];
